INSERT INTO `posts` (`id`, `title`, `slug`, `content`, `thumbnail`, `status`, `author_id`, `created_at`, `updated_at`, `category_id`, `place_id`, `tags`, `reading_time`) VALUES
(1, 'test blog', 'test-blog', 'test exemple 1', 'https://images.pexels.com/photos/19813743/pexels-photo-19813743.jpeg', 'published', 1, '2026-03-01 15:05:42', '2026-04-07 17:56:21', 6, 3, 'test, essai, début', 2),
(3, 'Nouveau plan de circulation au centre-ville', 'nouveau-plan-circulation-centre-ville', 'La mairie d\'Angoulême a annoncé ce lundi la mise en place d\'un nouveau plan de circulation dans le centre-ville historique. Cette réorganisation vise à réduire le trafic automobile dans les rues piétonnes et à favoriser les mobilités douces. Les travaux débuteront en avril et dureront environ trois mois. Les habitants du centre sont invités à participer à une réunion publique le 15 mars prochain à l\'Hôtel de Ville. De nombreux commerçants ont exprimé leurs inquiétudes quant à l\'accessibilité de leurs boutiques pendant la période de travaux. La mairie a prévu un plan de déviation et une signalétique renforcée pour guider les visiteurs.', 'https://images.pexels.com/photos/33930787/pexels-photo-33930787.jpeg', 'published', 1, '2026-01-03 08:00:00', '2026-04-07 17:53:37', 1, 1, 'circulation,centre-ville,mobilité,travaux,mairie', 4),
(4, 'Budget 2026 de la ville voté à l\'unanimité', 'budget-2026-ville-vote-unanimite', 'Le conseil municipal d\'Angoulême a adopté le budget 2026 lors de sa séance du jeudi 8 janvier. Pour la première fois depuis dix ans, le vote a été unanime. Le budget s\'élève à 87 millions d\'euros, en hausse de 5% par rapport à l\'année précédente. Les priorités affichées sont l\'éducation, la transition écologique et la rénovation du patrimoine bâti. Le maire a salué cette cohésion exceptionnelle des élus, soulignant que les défis à relever nécessitent une ville unie. L\'opposition a reconnu les efforts fournis tout en restant vigilante sur l\'exécution du budget.', 'https://images.pexels.com/photos/7735778/pexels-photo-7735778.jpeg', 'published', 1, '2026-01-08 09:00:00', '2026-04-07 17:55:00', 1, 1, 'budget,conseil-municipal,finances,mairie,2026', 3),
(5, 'Ouverture d\'une nouvelle médiathèque à Soyaux', 'ouverture-mediatheque-soyaux', 'La commune de Soyaux inaugurera sa nouvelle médiathèque le samedi 21 février 2026. Ce bâtiment de 1 200 m² a été conçu par un cabinet d\'architectes local. Il disposera d\'un espace dédié aux jeunes, d\'une salle de conférence et d\'une zone numérique avec douze postes informatiques en libre accès. La médiathèque proposera également des ateliers hebdomadaires d\'initiation au numérique pour les seniors. L\'investissement total s\'élève à 2,3 millions d\'euros, financé à 40% par la région Nouvelle-Aquitaine.', 'https://images.pexels.com/photos/20746514/pexels-photo-20746514.jpeg', 'published', 1, '2026-01-10 10:00:00', '2026-04-07 17:57:33', 1, 5, 'médiathèque,Soyaux,culture,Grand-Angoulême,inauguration', 3),
(6, 'La Charente franchit les seuils d\'alerte', 'charente-franchit-seuils-alerte', 'Suite aux fortes pluies des derniers jours, le niveau de la Charente a atteint le seuil d\'alerte ce mercredi matin. La préfecture de Charente a activé le plan de prévention des inondations. Les riverains des zones basses d\'Angoulême et de Cognac sont invités à prendre les précautions nécessaires. Les services techniques de la ville ont commencé à installer des batardeaux aux points sensibles. La situation devrait évoluer favorablement d\'ici la fin de la semaine selon Météo France, qui annonce une accalmie pour le week-end.', 'https://images.pexels.com/photos/17682749/pexels-photo-17682749.jpeg', 'published', 1, '2026-01-12 07:30:00', '2026-04-07 17:58:36', 1, 2, 'inondations,Charente,alerte,météo,préfecture', 4),
(7, 'Rénovation de la rue de Périgueux annoncée', 'renovation-rue-perigueux-annoncee', 'La rue de Périgueux va faire peau neuve. La mairie d\'Angoulême a officialisé le lancement des travaux de rénovation de cet axe majeur du nord de la ville. Au programme : réfection de la chaussée, création de pistes cyclables bidirectionnelles, plantation d\'arbres et rénovation de l\'éclairage public. Le coût total du projet est estimé à 1,8 million d\'euros. Les travaux sont prévus de juin à novembre 2026. Une concertation publique sera organisée en avril pour recueillir les avis des riverains et des usagers.', 'https://images.pexels.com/photos/33484882/pexels-photo-33484882.jpeg', 'published', 1, '2026-01-15 08:30:00', '2026-04-07 18:00:00', 1, 1, 'travaux,voirie,rue,mobilité,aménagement', 3),
(8, 'Angoulême candidat au label Ville Amie des Enfants', 'angouleme-candidat-label-ville-amie-enfants', 'La ville d\'Angoulême a officiellement déposé sa candidature au label UNICEF \"Ville Amie des Enfants\". Ce label récompense les communes qui s\'engagent dans une politique locale en faveur des droits de l\'enfant. Le dossier met en avant les nombreuses actions menées ces dernières années : espaces de jeux rénovés, programme de lutte contre le harcèlement scolaire, et création d\'un conseil municipal des jeunes. La réponse de l\'UNICEF est attendue pour le mois de mai.', 'https://images.pexels.com/photos/8422105/pexels-photo-8422105.jpeg', 'published', 1, '2026-01-18 09:00:00', '2026-04-07 18:05:35', 1, 1, 'enfants,UNICEF,label,politique,jeunesse', 3),
(9, 'Nouveau commissariat pour Angoulême en 2027', 'nouveau-commissariat-angouleme-2027', 'Le ministre de l\'Intérieur a confirmé lors d\'un déplacement en Charente que la construction du nouveau commissariat central d\'Angoulême débuterait au premier trimestre 2027. Le bâtiment actuel, vétuste et inadapté, sera remplacé par une structure moderne de 3 500 m² rue de Bordeaux. Ce projet, attendu depuis plus de dix ans par les forces de l\'ordre locales, représente un investissement de 12 millions d\'euros. Il devrait accueillir 280 fonctionnaires de police.', 'https://images.pexels.com/photos/9992726/pexels-photo-9992726.jpeg', 'published', 1, '2026-01-20 10:00:00', '2026-04-07 18:03:54', 1, 1, 'police,commissariat,sécurité,construction,2027', 4),
(10, 'La grève des transports urbains reconduite', 'greve-transports-urbains-reconduite', 'Le mouvement de grève au sein de la STGA (Société des Transports du Grand Angoulême) a été reconduit pour la troisième semaine consécutive. Les conducteurs réclament une revalorisation salariale de 8% et l\'amélioration des conditions de travail. Le service est assuré à hauteur de 30% seulement, perturbant fortement les déplacements des usagers. La direction et les syndicats se retrouveront en médiaton ce vendredi. La mairie a mis en place un service de navettes gratuites sur les lignes les plus fréquentées.', 'https://images.pexels.com/photos/19681019/pexels-photo-19681019.jpeg', 'published', 1, '2026-01-22 07:00:00', '2026-04-07 18:07:47', 1, 1, 'grève,transports,STGA,bus,social', 4),
(11, 'Plan de sobriété énergétique : bilan positif', 'plan-sobriete-energetique-bilan-positif', 'La ville d\'Angoulême publie un bilan encourageant de son plan de sobriété énergétique mis en place en 2024. La consommation d\'énergie des bâtiments municipaux a baissé de 18% en deux ans. L\'extinction nocturne de l\'éclairage public entre 1h et 5h du matin, contestée au début, a permis d\'économiser 240 000 euros annuels. Les panneaux photovoltaïques installés sur six écoles primaires couvrent désormais 40% de leurs besoins en électricité.', 'https://images.pexels.com/photos/18312457/pexels-photo-18312457.jpeg', 'published', 1, '2026-01-25 08:00:00', '2026-04-07 18:09:12', 1, 1, 'énergie,sobriété,écologie,économies,bilan', 4),
(12, 'Angoulême accueille le Congrès des Maires', 'angouleme-accueille-congres-maires', 'Angoulême a été choisie pour accueillir le Congrès Régional des Maires de Nouvelle-Aquitaine les 14 et 15 mars 2026. Près de 400 élus locaux sont attendus au Palais des Congrès. Au programme : ateliers thématiques sur la transition écologique, le numérique et le logement, table ronde sur les finances locales et discours du président de la région. Cet événement représente un enjeu important pour le rayonnement d\'Angoulême au sein de la grande région.', 'https://images.pexels.com/photos/32388389/pexels-photo-32388389.jpeg', 'published', 1, '2026-01-28 09:30:00', '2026-04-07 18:10:58', 1, 5, 'congrès,maires,Nouvelle-Aquitaine,politique,élus', 3),
(13, 'Déploiement de la fibre optique terminé', 'deploiement-fibre-optique-termine', 'La totalité des foyers de la commune d\'Angoulême est désormais éligible à la fibre optique. L\'opérateur Axione, mandaté par le conseil départemental, a achevé les travaux de déploiement qui ont duré trois ans. Angoulême devient ainsi l\'une des premières villes de taille moyenne de France à atteindre 100% de couverture fibre. Le taux de souscription atteint déjà 68% et continue de progresser chaque mois.', 'https://images.pexels.com/photos/1624895/pexels-photo-1624895.jpeg', 'published', 1, '2026-02-01 08:00:00', '2026-04-07 18:11:48', 1, 1, 'fibre,numérique,internet,haut-débit,technologie', 3),
(14, 'Ouverture d\'un nouveau marché bio place Bouillaud', 'nouveau-marche-bio-place-bouillaud', 'Un nouveau marché bio s\'installe place Bouillaud tous les samedis matin à partir du 7 mars. Une vingtaine de producteurs locaux certifiés Agriculture Biologique proposeront fruits, légumes, fromages, viandes et produits transformés. Ce marché s\'inscrit dans la politique de promotion des circuits courts portée par la municipalité. L\'accès sera entièrement piéton et un parking vélo sécurisé sera mis à disposition des clients.', 'https://images.pexels.com/photos/11669641/pexels-photo-11669641.jpeg', 'published', 1, '2026-02-03 10:00:00', '2026-04-07 18:12:35', 1, 1, 'marché,bio,local,alimentation,producteurs', 3),
(15, 'La piscine municipale fermée pour travaux', 'piscine-municipale-fermee-travaux', 'La piscine municipale des Bassins fermera ses portes du 16 mars au 30 juin pour une rénovation complète. Les vestiaires, les plages et le système de filtration seront entièrement remis à neuf. Le bassin olympique bénéficiera d\'un nouveau revêtement. Pendant la fermeture, les clubs sportifs seront redirigés vers la piscine de L\'Isle-d\'Espagnac. La réouverture est prévue pour le 1er juillet, juste avant la période estivale.', 'https://images.pexels.com/photos/8028328/pexels-photo-8028328.jpeg', 'published', 1, '2026-02-05 09:00:00', '2026-04-07 18:13:14', 1, 1, 'piscine,sport,travaux,rénovation,fermeture', 3),
(16, 'Recrutement de 25 agents municipaux', 'recrutement-25-agents-municipaux', 'La ville d\'Angoulême lance une campagne de recrutement pour 25 postes d\'agents municipaux. Les profils recherchés couvrent des domaines variés : agents d\'entretien, animateurs périscolaires, agents techniques de voirie et policiers municipaux. Les candidatures sont ouvertes jusqu\'au 28 février sur le site officiel de la ville. Des sessions d\'information seront organisées à la Maison de l\'Emploi les 12 et 19 février.', 'https://images.pexels.com/photos/10438560/pexels-photo-10438560.jpeg', 'published', 1, '2026-02-08 08:00:00', '2026-04-07 18:16:02', 1, 1, 'emploi,recrutement,mairie,fonctionnaire,offre', 3),
(17, 'Le festival BD approche : tout ce qu\'il faut savoir', 'festival-bd-approche-tout-savoir', 'Le Festival International de la Bande Dessinée d\'Angoulême se tiendra du 29 janvier au 1er février 2026. Plus de 200 000 visiteurs sont attendus dans la capitale mondiale de la BD. Cette année, le Grand Prix sera remis à une autrice japonaise dont les œuvres ont marqué la génération des années 2000. Retrouvez dans cet article toutes les infos pratiques : horaires, tarifs, accès, expositions à ne pas manquer et dédicaces des auteurs invités.', 'https://images.pexels.com/photos/34028150/pexels-photo-34028150.jpeg', 'published', 1, '2026-01-27 07:00:00', '2026-04-07 18:20:04', 1, 1, 'BD,festival,FIBD,Angoulême,manga,bande-dessinée', 5),
(18, 'Hausse des tarifs de stationnement au 1er mars', 'hausse-tarifs-stationnement-mars', 'La ville d\'Angoulême revoit ses tarifs de stationnement payant à la hausse à compter du 1er mars 2026. Le tarif de la première heure passe de 1,20€ à 1,50€. Le stationnement résidentiel augmente quant à lui de 15€ à 18€ par mois. La mairie justifie cette hausse par la nécessité de financer l\'entretien des parkings souterrains et le développement des alternatives à la voiture. Les tarifs du parking des remparts restent inchangés.', 'https://images.pexels.com/photos/36289710/pexels-photo-36289710.jpeg', 'published', 1, '2026-02-10 09:30:00', '2026-04-07 18:22:07', 1, 1, 'stationnement,parking,tarifs,voiture,mobilité', 3),
(19, 'Lancement du Pass Culture Local', 'lancement-pass-culture-local', 'Angoulême lance son propre Pass Culture Local, complémentaire au Pass Culture national. Ce dispositif, doté d\'un budget de 300 000 euros, permettra aux jeunes Angoumoisins de 15 à 25 ans de bénéficier de 50 euros supplémentaires pour accéder aux offres culturelles locales : cinémas, théâtres, librairies et musées de la ville. Les inscriptions ouvrent le 1er mars sur le site de la mairie.', 'https://images.pexels.com/photos/29057031/pexels-photo-29057031.jpeg', 'published', 1, '2026-02-12 10:00:00', '2026-04-07 18:23:49', 1, 1, 'culture,jeunesse,pass,art,cinéma,théâtre', 3),
(20, 'Travaux de réfection du Pont Saint-Cybard', 'travaux-pont-saint-cybard', 'Le pont Saint-Cybard sera partiellement fermé à la circulation du 10 mars au 15 mai pour des travaux de réfection de la chaussée et de renforcement de la structure. Une circulation alternée sera mise en place avec des feux tricolores. Les poids lourds seront déviés par le pont de Basseau. La mairie invite les automobilistes à anticiper leurs trajets et à privilégier les transports en commun pendant cette période.', 'https://images.pexels.com/photos/35007045/pexels-photo-35007045.jpeg', 'published', 1, '2026-02-15 08:00:00', '2026-04-07 18:25:27', 1, 1, 'pont,travaux,circulation,Charente,voirie', 3),
(21, 'La maison de santé de La Couronne inaugurée', 'maison-sante-la-couronne-inauguree', 'La nouvelle maison de santé pluridisciplinaire de La Couronne a été inaugurée samedi par le maire et le président de la communauté d\'agglomération. Ce pôle de santé regroupe quatre médecins généralistes, deux infirmiers, un kinésithérapeute et un orthophoniste. Il répond aux besoins d\'un territoire qui souffrait d\'une importante pénurie médicale depuis plusieurs années. Le bâtiment, entièrement accessible aux personnes à mobilité réduite, est ouvert du lundi au samedi.', 'https://images.pexels.com/photos/5215013/pexels-photo-5215013.jpeg', 'published', 1, '2026-02-18 09:00:00', '2026-04-07 18:28:06', 1, 5, 'santé,médecin,maison-de-santé,La-Couronne,inauguration', 4),
(22, 'Angoulême primée pour sa gestion des déchets', 'angouleme-primee-gestion-dechets', 'La ville d\'Angoulême a reçu le Prix National de la Gestion Durable des Déchets décerné par l\'ADEME. Cette distinction récompense les efforts engagés depuis 2022 : développement de la collecte sélective, création de ressourceries, composteurs collectifs dans les quartiers et campagnes de sensibilisation dans les écoles. Le taux de déchets recyclés a bondi de 31% à 49% en quatre ans, un record pour une ville de cette taille.', 'https://images.pexels.com/photos/6990304/pexels-photo-6990304.jpeg', 'published', 1, '2026-02-20 10:00:00', '2026-04-07 18:28:40', 1, 1, 'déchets,recyclage,écologie,prix,ADEME', 4),
(23, 'Réouverture du Musée des Beaux-Arts après rénovation', 'reouverture-musee-beaux-arts', 'Fermé depuis dix-huit mois pour une rénovation complète, le Musée des Beaux-Arts d\'Angoulême rouvre ses portes samedi 28 février. Les collections permanentes ont été entièrement réaccrochées selon une scénographie repensée. Une salle entièrement dédiée aux artistes charentais du XXe siècle fait son apparition. Le musée proposera également des nocturnes le premier vendredi de chaque mois et des ateliers pour les enfants chaque mercredi après-midi.', 'https://images.pexels.com/photos/18088640/pexels-photo-18088640.jpeg', 'published', 1, '2026-02-22 08:30:00', '2026-04-07 18:29:49', 1, 1, 'musée,art,réouverture,rénovation,culture,patrimoine', 4),
(24, 'Journée sans voiture le 22 mars', 'journee-sans-voiture-22-mars', 'Angoulême organise sa première Journée Sans Voiture le dimanche 22 mars 2026. Le centre-ville sera entièrement fermé à la circulation motorisée de 10h à 18h. Des animations sont prévues : balade à vélo guidée, marché artisanal, concerts de rue et initiation à la trottinette électrique. Toutes les lignes de bus seront gratuites ce jour-là. La mairie espère que cette initiative deviendra un rendez-vous mensuel si l\'accueil du public est positif.', 'https://images.pexels.com/photos/7958605/pexels-photo-7958605.jpeg', 'published', 1, '2026-02-25 09:00:00', '2026-04-07 18:32:12', 1, 1, 'voiture,mobilité,écologie,centre-ville,événement', 3),
(25, 'Projet de téléphérique urbain : étude de faisabilité lancée', 'projet-telepherique-urbain-etude', 'La mairie d\'Angoulême a officiellement lancé une étude de faisabilité pour la création d\'un téléphérique urbain reliant la gare SNCF au plateau central. Ce projet, présenté lors du conseil municipal, vise à résoudre la problématique de la dénivellation importante entre la ville basse et la ville haute. L\'étude, confiée à un bureau d\'ingénierie lyonnais, durera six mois et coûtera 180 000 euros. Les résultats seront présentés à l\'automne.', 'https://images.pexels.com/photos/29698890/pexels-photo-29698890.jpeg', 'draft', 1, '2026-03-01 08:00:00', NULL, 1, 1, 'téléphérique,transport,mobilité,innovation,étude', 5),
(27, 'Nouveau partenariat avec la ville de Darmstadt', 'nouveau-partenariat-ville-darmstadt', 'Angoulême et la ville allemande de Darmstadt vont renforcer leur partenariat de jumelage existant depuis 1960. Un accord-cadre portant sur les échanges culturels, scolaires et économiques sera signé lors d\'une cérémonie en avril. Les deux villes prévoient notamment des échanges de lycéens, un festival croisé autour de la bande dessinée et du design graphique, ainsi qu\'une coopération entre leurs incubateurs de startups.', 'https://images.pexels.com/photos/33175650/pexels-photo-33175650.jpeg', 'draft', 1, '2026-03-03 10:00:00', NULL, 1, 6, 'jumelage,Darmstadt,Europe,partenariat,culture', 4),
(28, 'La ZAC de Ma Campagne prend forme', 'zac-ma-campagne-prend-forme', 'Le chantier de la Zone d\'Aménagement Concerté de Ma Campagne avance à bon rythme. Ce nouveau quartier mixte en construction au nord de la ville comptera à terme 850 logements, un groupe scolaire, des commerces de proximité et un parc de 3 hectares. Les premiers habitants devraient emménager fin 2026. Le quartier sera entièrement raccordé à la fibre et doté d\'un réseau de chaleur urbaine alimenté par une chaufferie bois.', 'https://images.pexels.com/photos/5511065/pexels-photo-5511065.jpeg', 'draft', 1, '2026-03-04 08:30:00', '2026-04-07 19:16:51', 1, 1, 'urbanisme,logement,ZAC,quartier,construction', 5),
(29, 'Le théâtre de la Coupe d\'Or présente sa saison 2026', 'theatre-coupe-or-saison-2026', 'Le théâtre municipal de la Coupe d\'Or dévoile une saison 2026 particulièrement riche. Au programme : 24 spectacles allant du théâtre classique à la danse contemporaine en passant par le jeune public. La saison s\'ouvrira en septembre avec une création mondiale d\'une pièce d\'un auteur angoumoisin. Les abonnements sont disponibles dès maintenant au guichet ou sur le site du théâtre. Tarifs préférentiels pour les moins de 26 ans et les demandeurs d\'emploi.', 'https://images.pexels.com/photos/36359606/pexels-photo-36359606.jpeg', 'published', 2, '2026-01-06 09:00:00', NULL, 5, 1, 'théâtre,spectacle,culture,saison,Angoulême', 4),
(30, 'Exposition Moebius au CNBDI jusqu\'en avril', 'exposition-moebius-cnbdi-avril', 'La Cité Internationale de la Bande Dessinée et de l\'Image consacre une grande rétrospective à Jean Giraud dit Moebius, l\'un des maîtres incontestés du 9e art. L\'exposition rassemble plus de 200 planches originales, croquis et documents inédits retraçant cinquante ans de carrière. Elle sera visible jusqu\'au 26 avril. Des visites guidées sont proposées le week-end et des ateliers de dessin animés par des auteurs professionnels ont lieu chaque samedi matin.', 'https://images.pexels.com/photos/30484348/pexels-photo-30484348.jpeg', 'published', 2, '2026-01-10 08:00:00', NULL, 5, 1, 'BD,Moebius,exposition,CNBDI,dessin,9e-art', 4),
(31, 'Le cinéma Méga CGR rénove deux de ses salles', 'cinema-mega-cgr-renovation-salles', 'Le multiplexe CGR d\'Angoulême va procéder à la rénovation de ses salles 3 et 4 en mars. Ces deux salles de 280 et 350 places bénéficieront d\'un nouveau système de projection laser 4K et d\'une sonorisation Dolby Atmos. La rénovation durera trois semaines et n\'affectera pas les autres salles. CGR en profite pour annoncer l\'ouverture d\'une salle IMAX pour 2027, ce qui ferait d\'Angoulême l\'une des rares villes moyennes de France à disposer de ce format.', 'https://images.pexels.com/photos/14746411/pexels-photo-14746411.jpeg', 'published', 3, '2026-01-15 10:00:00', NULL, 5, 1, 'cinéma,CGR,rénovation,IMAX,4K,film', 3),
(32, 'Nuit des Musées 2026 : le programme angoumoisin', 'nuit-musees-2026-programme', 'La Nuit Européenne des Musées se tiendra le 16 mai 2026. Angoulême propose un programme exceptionnel cette année. Le Musée des Beaux-Arts ouvrira ses portes de 18h à minuit avec des visites théâtralisées et une performance de danse contemporaine dans ses salles. La CIBDI proposera une lecture de BD à voix haute par des auteurs invités. Le musée de la Résistance organisera une veillée commémorative avec témoignages.', 'https://images.pexels.com/photos/27084699/pexels-photo-27084699.jpeg', 'published', 2, '2026-01-20 09:30:00', NULL, 5, 1, 'musée,nuit,culture,visite,événement', 4),
(33, 'Les Correspondances de Manosque s\'exportent à Angoulême', 'correspondances-manosque-angouleme', 'Inspirée du célèbre festival littéraire de Manosque, une déclinaison locale baptisée \"Les Correspondances d\'Angoulême\" verra le jour en octobre 2026. Cet événement dédié à la littérature contemporaine accueillera une vingtaine d\'auteurs pour des rencontres, lectures et débats pendant trois jours. L\'initiative est portée par les libraires indépendants de la ville en partenariat avec la bibliothèque municipale.', 'https://images.pexels.com/photos/28676915/pexels-photo-28676915.jpeg', 'published', 2, '2026-01-25 08:00:00', NULL, 5, 1, 'littérature,festival,livres,auteurs,lecture', 3),
(34, 'Ouverture d\'une galerie d\'art contemporain rue Marengo', 'ouverture-galerie-art-contemporain-marengo', 'Une nouvelle galerie d\'art contemporain ouvre ses portes rue Marengo. La Galerie des Remparts, fondée par deux artistes locaux, proposera des expositions temporaires renouvelées tous les deux mois. L\'inauguration aura lieu le vendredi 6 février avec le vernissage d\'une exposition collective réunissant dix plasticiens de la région. Entrée libre. La galerie sera également un espace de médiation artistique avec des ateliers ouverts au public.', 'https://images.pexels.com/photos/14233204/pexels-photo-14233204.jpeg', 'published', 3, '2026-02-01 09:00:00', NULL, 5, 1, 'art,galerie,contemporain,vernissage,peinture', 3),
(35, 'Le Conservatoire fête ses 150 ans', 'conservatoire-fete-150-ans', 'Le Conservatoire à Rayonnement Régional d\'Angoulême célèbre ses 150 ans d\'existence cette année. Une série de concerts gratuits ouverts au public est programmée tout au long de l\'année. Le point d\'orgue sera un grand concert anniversaire au Théâtre de la Coupe d\'Or en juin, réunissant élèves, anciens élèves et professeurs. Une exposition photographique retraçant l\'histoire de l\'établissement sera visible dans le hall du conservatoire dès le 1er mars.', 'https://images.pexels.com/photos/35061318/pexels-photo-35061318.jpeg', 'published', 2, '2026-02-05 10:00:00', NULL, 5, 1, 'musique,conservatoire,anniversaire,concert,art', 4),
(36, 'Rencontre avec Riad Sattouf au FIBD', 'rencontre-riad-sattouf-fibd', 'L\'auteur de L\'Arabe du futur était l\'une des stars du dernier festival international de la BD. Riad Sattouf a accordé une heure de rencontre avec le public dans la grande salle du Palais des Congrès. Il a évoqué ses projets en cours, sa vision de la bande dessinée autobiographique et l\'adaptation de son œuvre au cinéma. Retour sur une rencontre passionnante avec l\'un des auteurs les plus populaires de sa génération.', 'https://images.pexels.com/photos/8342265/pexels-photo-8342265.jpeg', 'published', 3, '2026-01-30 13:00:00', NULL, 5, 1, 'BD,FIBD,auteur,rencontre,bande-dessinée', 5),
(37, 'Atelier sérigraphie à la Nef', 'atelier-serigraphie-nef', 'La salle de spectacles la Nef propose depuis ce mois un atelier sérigraphie ouvert à tous les niveaux le mercredi après-midi. Encadrés par un artiste professionnel, les participants apprennent à créer leurs propres motifs et à les imprimer sur tissu ou papier. Les séances durent deux heures et les matériaux sont fournis. Tarif : 15€ par séance. Réservation obligatoire sur le site de la Nef.', 'https://images.pexels.com/photos/17046295/pexels-photo-17046295.jpeg', 'published', 2, '2026-02-10 09:00:00', NULL, 5, 1, 'atelier,sérigraphie,art,impression,créativité', 3),
(38, 'Le Carnaval d\'Angoulême défile samedi', 'carnaval-angouleme-defile-samedi', 'Le traditionnel carnaval d\'Angoulême investira les rues du centre-ville samedi prochain. Une trentaine de chars défileront sur le parcours habituel partant de la place Bouillaud pour rejoindre les remparts. Le thème de cette année est \"Les Mondes Imaginaires\". La retraite aux flambeaux aura lieu en soirée à partir de 20h. Le feu du roi sera allumé à 21h30 place du Champ de Mars. Entrée gratuite pour tout le monde.', 'https://images.pexels.com/photos/36213502/pexels-photo-36213502.jpeg', 'published', 3, '2026-02-15 08:30:00', '2026-04-07 19:33:04', 5, 1, 'carnaval,fête,défilé,chars,tradition', 4),
(39, 'Nouveau spectacle son et lumière sur la cathédrale', 'spectacle-son-lumiere-cathedrale', 'À partir du printemps, la cathédrale Saint-Pierre accueillera chaque vendredi et samedi soir un spectacle son et lumière. Ce mapping vidéo projeté sur la façade romane retracera l\'histoire d\'Angoulême en douze séquences. Le spectacle, d\'une durée de 25 minutes, aura lieu à 21h de mars à juin et à 22h de juillet à septembre. Entrée libre. Ce projet a été conçu par une équipe de créateurs numériques angoumoisins.', 'https://images.pexels.com/photos/5567921/pexels-photo-5567921.jpeg', 'published', 2, '2026-02-20 09:00:00', '2026-04-07 19:36:59', 5, 1, 'cathédrale,son-et-lumière,spectacle,patrimoine,numérique', 4),
(40, 'Le Salon du Livre Jeunesse revient en mars', 'salon-livre-jeunesse-mars', 'Le Salon du Livre et de la Lecture Jeunesse d\'Angoulême se tiendra les 21 et 22 mars à l\'espace Carat. Plus de 60 auteurs et illustrateurs seront présents pour des dédicaces, lectures et ateliers créatifs. L\'entrée est gratuite pour les enfants de moins de 12 ans. Des animations spéciales sont prévues pour les classes qui souhaiteraient visiter le salon dans le cadre scolaire. Les réservations pour les groupes scolaires sont ouvertes.', 'https://images.pexels.com/photos/7307945/pexels-photo-7307945.jpeg', 'published', 3, '2026-02-22 10:00:00', '2026-04-07 19:37:48', 5, 1, 'livre,jeunesse,salon,lecture,enfants,illustrateur', 3),
(41, 'Création d\'une école de cirque à Angoulême', 'creation-ecole-cirque-angouleme', 'Le projet d\'une école municipale des arts du cirque avance concrètement. La mairie a identifié un bâtiment industriel désaffecté dans le quartier de La Grand-Font qui pourrait accueillir ce projet. L\'école proposerait des cours d\'acrobatie, jonglage, trapèze et clown pour tous les âges. Une consultation publique sera lancée au printemps pour recueillir les avis des habitants avant toute décision définitive.', 'https://images.pexels.com/photos/35333259/pexels-photo-35333259.jpeg', 'draft', 2, '2026-03-01 09:00:00', NULL, 5, 1, 'cirque,école,arts,culture,projet', 4),
(42, 'Festival Garorock : Angoulême en finale pour l\'accueil 2027', 'festival-garorock-angouleme-finale-2027', 'Angoulême est l\'une des trois villes finalistes pour accueillir l\'édition 2027 du festival Garorock, l\'un des grands festivals de musique du Sud-Ouest. La candidature angoumoisine met en avant le site des remparts et des espaces naturels disponibles à proximité du centre-ville. La décision des organisateurs est attendue pour le mois d\'avril. Si Angoulême est choisie, ce serait un événement majeur pour l\'attractivité touristique de la ville.', 'https://images.pexels.com/photos/11963114/pexels-photo-11963114.png', 'draft', 3, '2026-03-03 08:00:00', NULL, 5, 1, 'festival,musique,Garorock,candidature,événement', 4),
(43, 'L\'Angoulême CFC monte en Nationale', 'angouleme-cfc-monte-nationale', 'Victoire historique pour le football angoumoisin. L\'Angoulême CFC a officiellement obtenu sa montée en championnat National après sa victoire 3-1 face à Châtellerault samedi soir au stade Gérard Houllier. Cette promotion, la première depuis 1997, est accueillie avec une joie immense dans tout le département. Le président du club a promis des investissements significatifs pour maintenir le club dans cette nouvelle division.', 'https://images.pexels.com/photos/7188059/pexels-photo-7188059.jpeg', 'published', 4, '2026-01-08 17:00:00', NULL, 12, 1, 'football,ACFC,montée,Nationale,victoire', 4),
(44, 'Marathon du Grand Angoulême : inscriptions ouvertes', 'marathon-grand-angouleme-inscriptions', 'Les inscriptions pour la 12e édition du Marathon du Grand Angoulême sont désormais ouvertes. La course aura lieu le dimanche 5 avril. Le parcours de 42,195 km traversera les plus beaux paysages de l\'agglomération avec un passage par les remparts. Des épreuves complémentaires sont proposées : semi-marathon, 10 km et course enfants. Tarif d\'inscription : 45€ pour le marathon, 30€ pour le semi. Rendez-vous sur le site officiel.', 'https://images.pexels.com/photos/29400388/pexels-photo-29400388.jpeg', 'published', 4, '2026-01-15 09:00:00', NULL, 12, 5, 'marathon,course,running,sport,inscription', 3),
(45, 'Le Stado Aurillacois bat Angoulême Rugby en finale', 'stado-aurillacois-bat-angouleme-rugby', 'L\'équipe de rugby d\'Angoulême s\'est inclinée 18-14 en finale régionale face au Stado Aurillacois. Malgré une belle prestation des Charentais, les Aurillacois ont su renverser la vapeur en deuxième mi-temps grâce à une domination au niveau des avants. L\'entraîneur angoumoisin reste optimiste pour la suite de la saison et rappelle que cette finale démontre le niveau atteint par le club cette année.', 'https://images.pexels.com/photos/16566938/pexels-photo-16566938.jpeg', 'published', 4, '2026-01-22 19:00:00', NULL, 12, 2, 'rugby,finale,défaite,championnat,sport', 4),
(46, 'Nouveau complexe sportif prévu à Soyaux-Angoulême', 'nouveau-complexe-sportif-soyaux-angouleme', 'La communauté d\'agglomération du Grand Angoulême a validé le projet de construction d\'un nouveau complexe sportif intercommunal sur la commune de Soyaux. Ce futur équipement comprendra une salle omnisports de 2 000 places, une salle de combat et une piste d\'athlétisme couverte. Le coût est estimé à 18 millions d\'euros. Les travaux devraient débuter en 2027 pour une livraison en 2029.', 'https://images.pexels.com/photos/16828912/pexels-photo-16828912.jpeg', 'published', 4, '2026-02-01 10:00:00', NULL, 12, 5, 'sport,complexe,construction,équipement,intercommunal', 4),
(47, 'Championnat de France de judo à Angoulême en juin', 'championnat-france-judo-angouleme-juin', 'Angoulême accueillera le Championnat de France de Judo Jeunes les 13 et 14 juin 2026. Plus de 1 500 judokas de 15 à 18 ans sont attendus à l\'espace Carat. Cet événement d\'envergure nationale est une fierté pour le club angoumoisin, l\'un des plus titrés de la région. La billetterie sera ouverte au public et l\'entrée sera gratuite pour les enfants de moins de 12 ans accompagnés d\'un adulte.', 'https://images.pexels.com/photos/4392771/pexels-photo-4392771.jpeg', 'published', 4, '2026-02-10 09:00:00', NULL, 12, 1, 'judo,championnat,France,sport,jeunes', 3),
(48, 'Triathlètes angoumoisins podium aux Championnats régionaux', 'triathletes-angoumoisins-podium-regionaux', 'Le club de triathlon d\'Angoulême a brillé lors des Championnats régionaux de Nouvelle-Aquitaine qui se tenaient à Bordeaux ce week-end. Trois athlètes angoumoisins ont décroché des médailles : Léa Fontaine en or en catégorie espoir, Marc Durand en argent en senior et le relais mixte en bronze. Une performance collective exceptionnelle saluée par l\'ensemble de la communauté sportive locale.', 'https://images.pexels.com/photos/18457216/pexels-photo-18457216.jpeg', 'published', 4, '2026-02-16 18:00:00', '2026-04-07 19:48:25', 12, 5, 'triathlon,podium,championnat,sport,médaille', 3),
(49, 'Ouverture d\'une salle de padel au Grand Angoulême', 'ouverture-salle-padel-grand-angouleme', 'La première salle de padel professionnelle du Grand Angoulême ouvrira ses portes le 1er mars à L\'Isle-d\'Espagnac. Ce complexe de six terrains couvertes proposera des cours pour tous niveaux ainsi que des tournois hebdomadaires. Ce sport en plein essor séduit de plus en plus d\'amateurs de tennis et de squash. Les tarifs de location sont de 18€ par terrain et par heure en heures creuses.', 'https://images.pexels.com/photos/36246827/pexels-photo-36246827.jpeg', 'published', 4, '2026-02-22 09:00:00', '2026-04-07 19:49:50', 12, 5, 'padel,tennis,sport,ouverture,loisir', 3),
(50, 'Le Tour de Charente cycliste passe par Angoulême', 'tour-charente-cycliste-angouleme', 'Le Tour de Charente, course cycliste amateur organisée chaque printemps, traversera Angoulême le 29 mars. Le départ de la 3e étape sera donné depuis la place du Champ de Mars à 10h. Les coureurs emprunteront le boulevard Besson Bey et les remparts avant de prendre la direction de Cognac. Le public est invité à encourager les participants le long du parcours. Accès gratuit. Quelques perturbations du trafic sont à prévoir entre 9h30 et 11h.', 'https://images.pexels.com/photos/21588830/pexels-photo-21588830.jpeg', 'published', 4, '2026-03-01 08:00:00', '2026-04-07 19:50:28', 12, 2, 'cyclisme,Tour-de-Charente,vélo,sport,course', 3),
(101, 'Le off du Festival International de la Bande Dessinée d\'Angoulême 2026 : une édition record ?', 'festival-bd-angouleme-2026-edition-record', 'Le off du FIBD d\'Angoulême aura t\'il lieu dans les meilleures conditions et les passionnés seront ils au rendez-vous ? Plusieurs artistes ont répondu présent et des points d\'accueil seront identifiés dans toute la ville !', 'https://images.pexels.com/photos/36505525/pexels-photo-36505525.jpeg', 'published', 1, '2026-01-27 17:00:00', '2026-04-07 19:54:45', 5, 1, 'festival,BD,bande-dessinee,Angouleme,2026,culture', 12),
(102, 'La gastronomie charentaise à l\'honneur : nos meilleures adresses pour 2026', 'gastronomie-charentaise-meilleures-adresses-2026', 'La Charente est une terre de saveurs. Entre le cognac, le pineau, les huîtres de Marennes et le gâteau charentais, la région regorge de trésors culinaires. Cette année, plusieurs établissements ont été récompensés.', 'https://images.pexels.com/photos/30469692/pexels-photo-30469692.jpeg', 'published', 3, '2026-02-05 09:00:00', '2026-04-07 19:57:25', 5, 3, 'gastronomie,cuisine,restaurant,cognac,pineau,Charente', 10),
(103, 'Le patrimoine médiéval d\'Angoulême : remparts et cathédrale', 'patrimoine-medieval-angouleme-remparts-cathedrale', 'Perchée sur son promontoire rocheux, Angoulême dévoile un patrimoine médiéval d\'une richesse insoupçonnée. Des remparts gallo-romains jusqu\'à la cathédrale Saint-Pierre, la cité angoumoisine est un livre d\'histoire à ciel ouvert.', 'https://images.pexels.com/photos/30217827/pexels-photo-30217827.jpeg', 'published', 1, '2026-02-10 08:00:00', '2026-04-07 20:00:14', 3, 1, 'patrimoine,medieval,cathedrale,remparts,architecture,histoire', 15),
(104, 'Le marathon d\'Angoulême 2026 : 3 000 coureurs sur les routes charentaises', 'marathon-angouleme-2026-3000-coureurs', 'Dimanche 15 février, le coup de pistolet a retenti depuis la Place du Champ de Mars pour donner le départ du 12e Marathon d\'Angoulême. Cette année, 3 000 participants ont relevé le défi sur un parcours mêlant centre historique et vallée de la Charente.', 'https://images.pexels.com/photos/29596317/pexels-photo-29596317.jpeg', 'published', 4, '2026-02-15 18:00:00', '2026-04-07 20:01:29', 12, 1, 'marathon,sport,course,Angouleme,2026,running', 8),
(105, 'Rénovation du marché central d\'Angoulême : les travaux avancent', 'renovation-marche-central-angouleme-travaux', 'Inauguré en 1886, le marché central d\'Angoulême est l\'un des joyaux architecturaux de la ville. Après des années de débat, les travaux de rénovation ont démarré début janvier pour un budget de 18 millions d\'euros.', 'https://images.pexels.com/photos/17914082/pexels-photo-17914082.jpeg', 'published', 1, '2026-02-20 07:00:00', '2026-04-07 20:03:08', 1, 1, 'marche,renovation,travaux,patrimoine,architecture,centre-ville', 7),
(106, 'Découverte de la vallée de la Charente en kayak : guide complet', 'decouverte-vallee-charente-kayak-guide', 'La Charente est sans doute l\'un des fleuves les plus paisibles du Sud-Ouest. Serpentant à travers vignes et villages médiévaux, elle offre des parcours d\'une beauté époustouflante aux amateurs de kayak.', 'https://images.pexels.com/photos/2287353/pexels-photo-2287353.jpeg', 'published', 6, '2026-02-28 09:00:00', '2026-04-07 20:05:05', 12, 2, 'kayak,Charente,nature,sport,eau,riviere,plein-air', 11),
(107, 'L\'école de cirque d\'Angoulême : quand l\'art acrobatique rencontre la BD', 'ecole-cirque-angouleme-art-acrobatique-bd', 'Au carrefour du cirque contemporain et de la bande dessinée, l\'école de cirque d\'Angoulême propose depuis trois ans un projet pédagogique unique en France. Des acrobates travaillent main dans la main avec de futurs auteurs de BD.', 'https://images.pexels.com/photos/12398549/pexels-photo-12398549.jpeg', 'published', 3, '2026-03-01 10:00:00', '2026-04-07 20:07:22', 5, 1, 'cirque,ecole,acrobatie,culture,jeunesse,art,BD', 9),
(108, 'Le vignoble charentais : entre cognac, pineau et vins de pays', 'vignoble-charentais-cognac-pineau-vins-pays', 'La Charente est connue pour son cognac, exporté dans le monde entier. Mais derrière ce géant se cachent d\'autres trésors viticoles qui méritent leur place à la table des amateurs : pineau des Charentes et vins de pays.', 'https://images.pexels.com/photos/7270272/pexels-photo-7270272.jpeg', 'published', 1, '2026-03-08 08:00:00', '2026-04-07 20:07:59', 5, 3, 'cognac,pineau,vignoble,vin,Charente,gastronomie,terroir', 13),
(109, 'Angoulême accueille un nouveau lycée professionnel numérique', 'angouleme-nouveau-lycee-professionnel-numerique', 'La rentrée 2026 marquera une étape importante pour la formation professionnelle en Charente. Un nouveau lycée entièrement dédié aux métiers du numérique ouvrira ses portes en septembre dans le quartier de Sillac.', 'https://images.pexels.com/photos/5745513/pexels-photo-5745513.jpeg', 'published', 1, '2026-03-12 07:00:00', '2026-04-07 20:09:33', 1, 1, 'lycee,numerique,formation,education,Angouleme,tech', 6),
(110, 'Les jardins secrets d\'Angoulême : découvrez les espaces verts méconnus', 'jardins-secrets-angouleme-espaces-verts-meconnus', 'Derrière les façades de pierre du vieux Angoulême se cachent des oasis de verdure que peu de visiteurs connaissent. De l\'improbable jardin suspendu des remparts au jardin botanique du quartier Saint-Ausone.', 'https://images.pexels.com/photos/19613755/pexels-photo-19613755.jpeg', 'published', 9, '2026-03-18 09:00:00', '2026-04-07 20:10:35', 10, 1, 'jardins,nature,balade,Angouleme,plein-air,patrimoine,botanique', 8);
INSERT INTO `post_sections` (`id`, `post_id`, `type`, `content`, `media_url`, `position`) VALUES
(11, 1, 'text', 'Ceci est un article d\'essai pour voir si tout fonctionne bien, ce qui va permettre de corriger les erreurs et bugs éventuels qui pourraient se présenter et qu\'il faudra corriger.\r\nIl est important de repérer ces erreurs avant de valider le blog.', NULL, 0),
(12, 1, 'video', NULL, 'https://www.youtube.com/watch?v=MYMsL9Dtboc', 1),
(13, 1, 'title', 'Quel intreêt ?', NULL, 2),
(14, 1, 'text', 'Pour le lecteur, il n\'y en a aucun, mais pour moi c\'est primordial, je devrais pouvoir résoudre les quelques bugs auxquels je n\'ai pas pensés.', NULL, 3),
(15, 1, 'quote', 'C\'est en testant qu\'on devient testeur !', NULL, 4),
(349, 101, 'title', 'Une fréquentation historique', NULL, 1),
(350, 101, 'text', 'Le FIBD a fermé ses portes dimanche soir après quatre jours exceptionnels. Avec plus de 220 000 visiteurs, cette 53e édition s\'impose comme la plus fréquentée de la décennie. Les files d\'attente devant les stands témoignaient d\'un appétit intact pour le neuvième art.', NULL, 2),
(351, 101, 'image', 'Vue générale du festival depuis la Place du Champ de Mars', 'https://images.pexels.com/photos/1049399/pexels-photo-1049399.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(352, 101, 'title', 'Le Grand Prix décerné à Riad Sattouf', NULL, 4),
(353, 101, 'text', 'Le Grand Prix du festival, récompense suprême couronnant l\'ensemble d\'une carrière, a été attribué cette année à Riad Sattouf, auteur de la célèbre série L\'Arabe du futur. Cette distinction est décernée par les auteurs eux-mêmes lors d\'un vote. Sattouf présidera le festival l\'année prochaine.', NULL, 5),
(354, 101, 'quote', 'La bande dessinée est le seul art qui permet de faire du cinéma avec un stylo. C\'est sa force et sa magie.', NULL, 6),
(355, 101, 'title', 'Les expositions qui ont marqué les esprits', NULL, 7),
(356, 101, 'text', 'Parmi la soixantaine d\'expositions proposées, l\'exposition Moebius présentée à la Cité internationale de la bande dessinée a accueilli plus de 45 000 personnes en quatre jours. L\'installation immersive permettant aux visiteurs de se retrouver à l\'intérieur des planches originales a suscité une émotion palpable chez tous les visiteurs.', NULL, 8),
(357, 101, 'image', 'Exposition Moebius à la Cité internationale de la BD', 'https://images.pexels.com/photos/3109671/pexels-photo-3109671.jpeg?auto=compress&cs=tinysrgb&w=1200', 9),
(358, 101, 'video', 'Reportage sur le Festival de la BD d\'Angoulême 2026', 'https://www.youtube.com/watch?v=dQw4w9WgXcQ', 10),
(359, 101, 'title', 'Le marché de la BD en pleine forme', NULL, 11),
(360, 101, 'text', 'Les éditeurs présents ont unanimement salué une édition commerciale exceptionnelle. Les ventes ont progressé de 18% par rapport à l\'an dernier. Les petites maisons indépendantes, regroupées dans un hall dédié, ont particulièrement profité de cette dynamique positive.', NULL, 12),
(361, 102, 'title', 'Les incontournables de la table charentaise', NULL, 1),
(362, 102, 'text', 'La cuisine charentaise puise ses racines dans une tradition paysanne et maritime. Elle s\'appuie sur des produits d\'exception : beurre AOP Charentes-Poitou, huîtres de Marennes-Oléron, escargots de Bourgogne élevés en Charente. C\'est une cuisine de plaisir, sans chichi, qui fait la part belle à la convivialité.', NULL, 2),
(363, 102, 'image', 'Plateau de fruits de mer charentais', 'https://images.pexels.com/photos/1640777/pexels-photo-1640777.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(364, 102, 'title', 'Nos coups de coeur à Angoulême', NULL, 4),
(365, 102, 'text', 'La Table de Nil propose une cuisine gastronomique inspirée du terroir charentais revisité avec créativité. Le chef Nil Cakmak, formé à Lyon et passé par plusieurs étoilés parisiens, s\'est installé à Angoulême il y a trois ans pour une cuisine engagée, sourcée localement.', NULL, 5),
(366, 102, 'image', 'Chais de cognac dans les environs d\'Angoulême', 'https://images.pexels.com/photos/1407846/pexels-photo-1407846.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(367, 102, 'quote', 'Le pineau des Charentes, c\'est la douceur de notre terroir mis en bouteille. Un apéritif unique au monde.', NULL, 7),
(368, 102, 'title', 'Le marché du samedi : le rendez-vous des gourmands', NULL, 8),
(369, 102, 'text', 'Chaque samedi matin, le marché des Halles transforme Angoulême en festival de saveurs. Producteurs locaux, maraîchers, fromagers et charcutiers se côtoient dans une atmosphère festive. C\'est ici que bat le coeur de la gastronomie charentaise.', NULL, 9),
(370, 102, 'video', 'Visite du marché d\'Angoulême avec un chef local', 'https://www.youtube.com/watch?v=ScMzIvxBSi4', 10),
(371, 103, 'title', 'Angoulême, la ville aux cent clochers', NULL, 1),
(372, 103, 'text', 'Perchée sur son promontoire rocheux dominant la vallée de la Charente, Angoulême dévoile un patrimoine médiéval d\'une richesse insoupçonnée. Des remparts gallo-romains jusqu\'à la cathédrale Saint-Pierre, la cité angoumoisine est un livre d\'histoire à ciel ouvert.', NULL, 2),
(373, 103, 'image', 'Les remparts d\'Angoulême vus du ciel', 'https://images.pexels.com/photos/2363/france-landmark-lights-night.jpg?auto=compress&cs=tinysrgb&w=1200', 3),
(374, 103, 'title', 'La cathédrale Saint-Pierre : chef-d\'oeuvre roman', NULL, 4),
(375, 103, 'text', 'Construite entre le XIe et le XIIe siècle, la cathédrale Saint-Pierre est l\'un des plus beaux exemples de l\'art roman poitevin. Sa façade occidentale, décorée de plus de 70 sculptures représentant des scènes de l\'Apocalypse, est classée monument historique depuis 1840.', NULL, 5),
(376, 103, 'image', 'Façade de la cathédrale Saint-Pierre', 'https://images.pexels.com/photos/1796715/pexels-photo-1796715.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(377, 103, 'quote', 'Angoulême est une ville qui se mérite. Elle ne livre ses secrets qu\'à ceux qui acceptent de la regarder de près.', NULL, 7),
(378, 103, 'title', 'Les remparts : promenade panoramique', NULL, 8),
(379, 103, 'text', 'Les remparts forment une ceinture de 4,7 km autour du plateau. Aménagés en promenade au XIXe siècle, ils offrent des panoramas exceptionnels sur la vallée de la Charente et les coteaux de Soyaux. La promenade des remparts est l\'endroit préféré des Angoumoisins pour leur balade dominicale.', NULL, 9),
(380, 103, 'video', 'Visite du patrimoine médiéval d\'Angoulême', 'https://www.youtube.com/watch?v=9bZkp7q19f0', 10),
(381, 104, 'title', 'Un parcours au coeur de la Charente', NULL, 1),
(382, 104, 'text', 'Dimanche 15 février, le coup de pistolet a retenti à 9h30 depuis la Place du Champ de Mars. Cette année, l\'organisation a revu le parcours pour offrir aux 3 000 participants un tracé mêlant le coeur historique de la ville et les paysages de la vallée de la Charente.', NULL, 2),
(383, 104, 'image', 'Le départ du marathon depuis la Place du Champ de Mars', 'https://images.pexels.com/photos/2524531/pexels-photo-2524531.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(384, 104, 'title', 'Les résultats : podiums hommes et femmes', NULL, 4),
(385, 104, 'text', 'Chez les hommes, la victoire est revenue au Kenyan David Kiprop en 2h18\'34\'\'. La deuxième place a été décrochée par le Français Mehdi Doukkali (2h24\'11\'\'). Chez les dames, la Française Amandine Ferrer s\'est imposée en 2h42\'19\'\'.', NULL, 5),
(386, 104, 'image', 'Arrivée des premiers coureurs', 'https://images.pexels.com/photos/936094/pexels-photo-936094.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(387, 104, 'quote', 'Je cours depuis vingt ans mais jamais un public aussi chaleureux ne m\'avait accompagné. Angoulême, c\'est unique !', NULL, 7),
(388, 104, 'video', 'Résumé vidéo du Marathon d\'Angoulême 2026', 'https://www.youtube.com/watch?v=LXb3EKWsInQ', 8),
(389, 105, 'title', 'Un monument de fonte et de verre depuis 1886', NULL, 1),
(390, 105, 'text', 'Inauguré en 1886 sur le site de l\'ancienne église des Cordeliers, le marché central d\'Angoulême est l\'un des joyaux architecturaux de la ville. Sa structure en fonte et sa verrière zénithale en font un exemple remarquable de l\'architecture industrielle du XIXe siècle.', NULL, 2),
(391, 105, 'image', 'La façade du marché central', 'https://images.pexels.com/photos/1367243/pexels-photo-1367243.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(392, 105, 'title', 'Un projet de rénovation ambitieux', NULL, 4),
(393, 105, 'text', 'Le projet prévoit la restauration complète de la structure métallique, le remplacement de la verrière et la création d\'un nouveau hall dédié aux producteurs locaux en circuit court. Budget total : 18 millions d\'euros. Les travaux durent 18 mois.', NULL, 5),
(394, 105, 'quote', 'Ce marché, c\'est toute notre enfance. Hors de question de lui faire perdre son âme.', NULL, 6),
(395, 105, 'image', 'Intérieur du marché en cours de chantier', 'https://images.pexels.com/photos/2219024/pexels-photo-2219024.jpeg?auto=compress&cs=tinysrgb&w=1200', 7),
(396, 106, 'title', 'Pourquoi choisir la Charente pour votre aventure kayak', NULL, 1),
(397, 106, 'text', 'La Charente est sans doute l\'un des fleuves les plus paisibles du Sud-Ouest. Serpentant à travers vignes, prairies et villages médiévaux, elle offre aux amateurs de kayak des parcours d\'une beauté époustouflante, accessibles à des niveaux très variés.', NULL, 2),
(398, 106, 'image', 'Kayakiste sur la Charente', 'https://images.pexels.com/photos/1497586/pexels-photo-1497586.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(399, 106, 'title', 'Les parcours recommandés au départ d\'Angoulême', NULL, 4),
(400, 106, 'text', 'Le parcours découverte (8 km, 2h) longe les berges boisées jusqu\'au moulin de Fleurac. Le parcours patrimoine (15 km, 4h) relie Angoulême à Sireuil en passant par des châteaux médiévaux, offrant un point de vue unique sur le bâti de la région.', NULL, 5),
(401, 106, 'image', 'Coucher de soleil sur la Charente', 'https://images.pexels.com/photos/1165982/pexels-photo-1165982.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(402, 106, 'quote', 'Une heure sur la Charente en kayak vaut toutes les cures de détox du monde.', NULL, 7),
(403, 106, 'video', 'Descente de la Charente en kayak', 'https://www.youtube.com/watch?v=ePCFnMVK3ts', 8),
(404, 107, 'title', 'Un projet né d\'une rencontre improbable', NULL, 1),
(405, 107, 'text', 'Tout a commencé lors d\'une résidence artistique dans les anciennes usines Leroy à Angoulême. La circassienne Marie Villeneuve et l\'auteur de BD Chloé Favreau ont partagé un atelier pendant trois semaines. De cette cohabitation est né un projet commun et unique en France.', NULL, 2),
(406, 107, 'image', 'Répétition de l\'école de cirque', 'https://images.pexels.com/photos/1699414/pexels-photo-1699414.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(407, 107, 'title', 'Une pédagogie innovante', NULL, 4),
(408, 107, 'text', 'L\'école accueille 120 élèves de 8 à 18 ans. Une fois par mois, les élèves acrobates et les jeunes auteurs de BD travaillent ensemble autour d\'un thème commun. Les résultats sont exposés lors d\'une restitution publique qui attire chaque fois plus de 500 spectateurs.', NULL, 5),
(409, 107, 'quote', 'Quand un jongleur dessine ses propres trajectoires et qu\'un dessinateur essaie d\'attraper une massue, quelque chose de magique se passe.', NULL, 6),
(410, 108, 'title', 'Le cognac : l\'or de la Charente', NULL, 1),
(411, 108, 'text', 'La Charente est connue pour son cognac, exporté dans plus de 160 pays. Produit exclusivement dans une aire délimitée autour de Cognac, il est le résultat d\'un processus de distillation et de vieillissement qui peut prendre plusieurs décennies.', NULL, 2),
(412, 108, 'image', 'Vendanges dans les vignes charentaises', 'https://images.pexels.com/photos/1407846/pexels-photo-1407846.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(413, 108, 'title', 'Le pineau des Charentes : douceur et raffinement', NULL, 4),
(414, 108, 'text', 'Moins connu que son illustre cousin, le pineau des Charentes mérite toute l\'attention des amateurs. Cet apéritif est obtenu par le mélange de jus de raisin frais et de cognac, puis vieilli en fûts de chêne. Il se décline en blanc, rosé et rouge.', NULL, 5),
(415, 108, 'image', 'Chais de vieillissement du pineau', 'https://images.pexels.com/photos/2702805/pexels-photo-2702805.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(416, 108, 'quote', 'Un bon cognac, c\'est comme un roman : il faut du temps pour qu\'il révèle toute sa complexité.', NULL, 7),
(417, 108, 'video', 'Visite d\'un chai de cognac en Charente', 'https://www.youtube.com/watch?v=tVlcKp3bWH8', 8),
(418, 109, 'title', 'Un projet né des besoins du territoire', NULL, 1),
(419, 109, 'text', 'Le nouveau lycée professionnel dédié au numérique ouvrira ses portes en septembre 2026 dans le quartier de Sillac. Cet établissement de 6 500 m² accueillera 600 élèves dans huit filières : développement web, cybersécurité, design numérique, data et plus encore.', NULL, 2),
(420, 109, 'image', 'Maquette du futur lycée numérique', 'https://images.pexels.com/photos/256490/pexels-photo-256490.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(421, 109, 'title', 'Les huit filières proposées', NULL, 4),
(422, 109, 'text', 'Le lycée proposera : Développement Web et Web Mobile (DWWM), Gestionnaire de Systèmes d\'Information, Technicien Systèmes et Réseaux, Designer UI/UX, Data Analyst, Intelligence Artificielle, Cybersécurité et Maintenance de Systèmes Automatisés.', NULL, 5),
(423, 109, 'quote', 'La Charente a besoin de compétences numériques locales. Former nos jeunes ici, c\'est investir dans l\'avenir du territoire.', NULL, 6),
(424, 110, 'title', 'Le jardin des remparts : un panorama suspendu', NULL, 1),
(425, 110, 'text', 'Derrière les façades de pierre du vieux Angoulême se cachent des oasis de verdure que peu de visiteurs connaissent. Du jardin suspendu des remparts au jardin botanique du quartier Saint-Ausone, voici un guide pour explorer les poumons verts de la cité charentaise.', NULL, 2),
(426, 110, 'image', 'Jardin des remparts en été', 'https://images.pexels.com/photos/1072824/pexels-photo-1072824.jpeg?auto=compress&cs=tinysrgb&w=1200', 3),
(427, 110, 'title', 'Le jardin de l\'Hôtel de Ville', NULL, 4),
(428, 110, 'text', 'Peu de visiteurs savent que l\'Hôtel de Ville abrite dans ses douves un jardin à la française d\'une élégance certaine. Accessible librement en semaine, il permet de découvrir sous un autre angle les tours médiévales. En été, des concerts de musique de chambre y sont organisés.', NULL, 5),
(429, 110, 'image', 'Jardin botanique du quartier Saint-Ausone', 'https://images.pexels.com/photos/1022923/pexels-photo-1022923.jpeg?auto=compress&cs=tinysrgb&w=1200', 6),
(430, 110, 'quote', 'Ces jardins sont notre jardin secret à tous. Les Angoumoisins les gardent jalousement.', NULL, 7),
(431, 110, 'video', 'Balade dans les jardins secrets d\'Angoulême', 'https://www.youtube.com/watch?v=a1yFqPBBKbU', 8);
INSERT INTO `events` (`id`, `title`, `description`, `event_date`, `event_time`, `location`, `created_at`) VALUES
(1, 'Festival International de la Bande Dessinée', 'Le plus grand festival de BD au monde. 4 jours de rencontres, expositions, dédicaces et animations autour du 9e art.', '2026-04-29', '09:00:00', 'Cité Internationale de la BD, Angoulême', '2026-01-01 08:00:00'),
(2, 'Marathon du Grand Angoulême', 'Course sur 42km à travers les plus beaux paysages de l\'agglomération. Semi-marathon et 10km également au programme.', '2026-04-05', '08:30:00', 'Place du Champ de Mars, Angoulême', '2026-01-05 08:00:00'),
(3, 'Carnaval d\'Angoulême', 'Défilé de chars, retraite aux flambeaux et feu du roi. Thème 2026 : Les Mondes Imaginaires.', '2026-03-21', '14:00:00', 'Place Bouillaud, Angoulême', '2026-01-10 08:00:00'),
(4, 'Nuit des Musées', 'Ouverture nocturne gratuite de tous les musées d\'Angoulême avec animations et visites théâtralisées.', '2026-05-16', '18:00:00', 'Musées d\'Angoulême', '2026-01-15 08:00:00'),
(5, 'Championnat de France de Judo Jeunes', 'Plus de 1500 judokas de 15 à 18 ans s\'affrontent dans cet événement national.', '2026-06-13', '09:00:00', 'Espace Carat, Angoulême', '2026-01-20 08:00:00'),
(6, 'Concert anniversaire du Conservatoire 150 ans', 'Grand concert exceptionnel réunissant élèves, anciens élèves et enseignants pour fêter 150 ans d\'histoire musicale.', '2026-06-20', '20:00:00', 'Théâtre de la Coupe d\'Or, Angoulême', '2026-01-25 08:00:00'),
(7, 'Journée Sans Voiture', 'Centre-ville fermé aux voitures de 10h à 18h. Animations, vélos et transports gratuits.', '2026-03-22', '10:00:00', 'Centre-ville, Angoulême', '2026-02-01 08:00:00'),
(8, 'Salon du Livre Jeunesse', 'Deux jours de rencontres avec auteurs et illustrateurs. Ateliers créatifs pour les enfants.', '2026-03-21', '10:00:00', 'Espace Carat, Angoulême', '2026-02-05 08:00:00'),
(9, 'Spectacle Son et Lumière Cathédrale', 'Mapping vidéo sur la façade de la cathédrale Saint-Pierre retraçant l\'histoire d\'Angoulême.', '2026-04-10', '21:00:00', 'Cathédrale Saint-Pierre, Angoulême', '2026-02-10 08:00:00'),
(11, 'Tour de Charente Cycliste - Étape 3', 'Départ de l\'étape Angoulême-Cognac depuis la place du Champ de Mars.', '2026-03-29', '10:00:00', 'Place du Champ de Mars, Angoulême', '2026-02-15 08:00:00'),
(12, 'Marché de Noël Anticipé - Artisans Locaux', 'Marché des artisans et producteurs locaux avec plus de 80 exposants.', '2026-12-05', '10:00:00', 'Place de l\'Hôtel de Ville, Angoulême', '2026-02-20 08:00:00');
