INSERT INTO `comments` (`id`, `post_id`, `user_id`, `content`, `status`, `created_at`) VALUES
(2, 3, 2, 'Très bonne nouvelle pour notre ville ! J\'habitais dans ce quartier et la circulation était vraiment un problème. Vivement les travaux.', 'approved', '2026-01-04 09:00:00'),
(3, 3, 3, 'Je me demande comment les commerçants vont s\'en sortir pendant les travaux. La mairie aurait dû mieux les concerter en amont.', 'approved', '2026-01-04 13:00:00'),
(4, 3, 4, 'Enfin ! Ça fait des années qu\'on attendait ça. Bravo à la mairie pour cette initiative.', 'approved', '2026-01-05 08:00:00'),
(5, 3, 5, 'Super article, bien détaillé. Merci pour l\'info sur la réunion publique du 15 mars.', 'pending', '2026-01-05 15:00:00'),
(6, 30, 2, 'Magnifique exposition ! J\'y suis allé le week-end dernier et les planches originales sont époustouflantes. À voir absolument.', 'approved', '2026-01-12 10:00:00'),
(7, 30, 6, 'Moebius est un génie. Cette exposition rend vraiment hommage à son talent immense. Je vais y retourner.', 'approved', '2026-01-13 14:00:00'),
(8, 30, 3, 'L\'atelier du samedi matin est vraiment bien. L\'animateur est pédagogue et passionné.', 'approved', '2026-01-14 08:00:00'),
(9, 43, 4, 'Quelle joie immense ! Ça faisait tellement longtemps qu\'on attendait cette montée. Allez l\'ACFC !', 'approved', '2026-01-09 09:00:00'),
(10, 43, 5, 'J\'étais au stade hier soir, ambiance incroyable ! Toute la ville était là.', 'approved', '2026-01-09 11:00:00'),
(11, 43, 6, 'Fière d\'être Angoumoisine ce soir ! Quelle équipe formidable !', 'approved', '2026-01-09 17:00:00'),
(12, 18, 2, 'Cette hausse est vraiment excessive. Pourquoi toujours pénaliser les automobilistes ?', 'approved', '2026-02-11 08:00:00'),
(13, 18, 3, 'Je suis passée au vélo depuis deux ans, je ne regrette pas du tout ! Les tarifs de parking ne me concernent plus.', 'approved', '2026-02-11 13:00:00'),
(14, 18, 7, 'Commentaire en attente de modération — je trouve cette hausse injustifiée pour les habitants.', 'pending', '2026-02-12 09:00:00'),
(15, 17, 4, 'Superbe initiative ! La BD mérite vraiment ce type de mise en avant dans notre ville.', 'approved', '2026-01-28 10:00:00'),
(16, 17, 5, 'J\'ai hâte ! C\'est mon événement préféré de l\'année. On vient de loin pour y participer.', 'approved', '2026-01-28 14:00:00'),
(17, 44, 6, 'Excellent article sur le marathon ! Je suis inscrit et j\'ai hâte. C\'est ma première participation.', 'approved', '2026-01-16 09:00:00'),
(18, 44, 2, 'Superbe parcours l\'année dernière, j\'espère que celui de 2026 sera aussi beau.', 'approved', '2026-01-17 08:00:00'),
(19, 44, 8, 'Commentaire en attente — est-ce qu\'il y a une option marche nordique cette année ?', 'pending', '2026-01-18 10:00:00'),
(20, 24, 4, 'belle initiative pour redonner confiance aux piétions', 'rejected', '2026-03-08 12:30:58'),
(21, 1, 1, 'test commentaire', 'approved', '2026-03-21 09:32:16'),
(22, 101, 4, 'J\'y étais ! Une ambiance incroyable, j\'ai fait la queue deux heures pour une dédicace mais ça valait le coup. Le festival cette année était encore plus grand que l\'an dernier.', 'approved', '2026-01-28 08:00:00'),
(23, 101, 5, 'Le Grand Prix attribué à Riad Sattouf est amplement mérité. L\'Arabe du futur est une des séries les plus importantes de ces dernières années.', 'approved', '2026-01-28 10:00:00'),
(24, 101, 6, 'L\'exposition Moebius était époustouflante. Se retrouver à l\'intérieur d\'une planche originale, c\'est une expérience qu\'on n\'oublie pas.', 'approved', '2026-01-28 13:00:00'),
(25, 101, 7, 'Je regrette de ne pas avoir pu y aller cette année. L\'année prochaine avec Sattouf en président, ca promet !', 'approved', '2026-01-29 07:00:00'),
(26, 101, 9, 'Mon fils a découvert la BD grace au festival l\'année dernière. Cette année il est reparti avec une pile de livres. C\'est la vraie reussite du festival.', 'approved', '2026-01-29 09:00:00'),
(27, 101, 8, 'Est-ce qu\'il y aura des dedicaces speciales lors de l\'edition 2027 avec Sattouf ?', 'pending', '2026-01-30 08:00:00'),
(28, 102, 4, 'La Table de Nil est une decouverte extraordinaire. Le chef est venu a notre table pour expliquer d\'ou venaient les produits. Un moment inoubliable.', 'approved', '2026-02-05 13:00:00'),
(29, 102, 6, 'Le marche du samedi, c\'est toute mon enfance ! Triste de le voir ferme pour les travaux mais le marche temporaire est bien organise.', 'approved', '2026-02-06 08:00:00'),
(30, 102, 7, 'Je recommande la visite de la maison Frapin a Segonzac. Moins touristique que les grandes maisons mais le tour des chais est exceptionnel.', 'approved', '2026-02-06 10:00:00'),
(31, 102, 5, 'Le pineau des Charentes avec du melon charentais, c\'est l\'accord parfait. Simple, authentique, indemodable.', 'approved', '2026-02-07 09:00:00'),
(32, 103, 5, 'La cathedrale Saint-Pierre est un monument magnifique. J\'y amene tous mes amis qui viennent visiter Angouleme et ils sont systematiquement emerveilles.', 'approved', '2026-02-10 14:00:00'),
(33, 103, 9, 'Je vis a Angouleme depuis vingt ans et j\'apprends encore des choses sur ma ville grace a cet article. Merci pour ce travail de recherche.', 'approved', '2026-02-11 08:00:00'),
(34, 103, 4, 'Article tres bien documente ! Une correction : la cathedrale a aussi souffert de la Revolution qui l\'avait transformee en temple de la Raison.', 'approved', '2026-02-12 09:00:00'),
(35, 104, 5, 'J\'etais dans le peloton des 3h00 ! Quelle course magnifique. La montee des remparts au km 18 etait dure mais le soutien du public nous a portes.', 'approved', '2026-02-15 21:00:00'),
(36, 104, 6, 'J\'ai regarde ma soeur courir depuis le haut des remparts. L\'ambiance etait incroyable ! Voir ce flot de coureurs arriver, c\'etait tres emouvant.', 'approved', '2026-02-16 07:00:00'),
(37, 104, 8, 'Felicitations a tous les finishers ! Le marathon d\'Angouleme est en train de devenir un evenement vraiment important.', 'approved', '2026-02-16 09:00:00'),
(38, 104, 3, 'J\'ai essaye de m\'inscrire mais les places etaient toutes prises deux mois avant. Il faudrait augmenter la capacite.', 'pending', '2026-02-17 08:00:00'),
(39, 105, 4, 'Ce marche, c\'est le coeur d\'Angouleme. J\'espere que la renovation respectera l\'esprit du lieu.', 'approved', '2026-02-20 11:00:00'),
(40, 105, 6, 'Le marche temporaire est bien organise mais ca n\'a pas le meme charme. Vivement la reouverture !', 'approved', '2026-02-21 08:00:00'),
(41, 105, 7, 'La structure en fonte de 1886 est classee monument historique, donc elle ne peut pas etre modifiee substantiellement.', 'approved', '2026-02-22 09:00:00'),
(42, 106, 7, 'J\'ai fait le parcours patrimoine l\'ete dernier avec mes enfants. Un souvenir magnifique ! On a vu trois loutres pendant la descente.', 'approved', '2026-02-28 13:00:00'),
(43, 106, 5, 'Excellente idee pour les vacances. Est-ce que des debutants complets peuvent faire le parcours decouverte sans formation ?', 'approved', '2026-03-01 08:00:00'),
(44, 106, 8, 'La Charente est un tresor naturel sous-exploite. Le retour de la loutre est la preuve de l\'amelioration de la qualite de l\'eau.', 'approved', '2026-03-01 10:00:00'),
(45, 107, 6, 'J\'ai vu le spectacle de juin dernier au theatre. Ce que ces jeunes font est d\'un niveau professionnel. Le projet est une vraie reussite.', 'approved', '2026-03-01 14:00:00'),
(46, 107, 8, 'Mon neveu est inscrit a l\'ecole de cirque depuis deux ans. La transformation est remarquable : il a gagne en confiance et en creativite.', 'approved', '2026-03-02 08:00:00'),
(47, 108, 4, 'Merci pour cet article sur notre patrimoine viticole. Le cognac reste trop souvent percu comme un produit de luxe reserve aux etrangers.', 'approved', '2026-03-08 12:00:00'),
(48, 108, 7, 'Le pineau des Charentes avec du canard aux cepes, c\'est une alliance que je recommande. Le cote sucre-boise s\'accorde parfaitement.', 'approved', '2026-03-09 08:00:00'),
(49, 108, 5, 'La Route du Cognac a velo est une experience magnifique. J\'ai fait les 100 km l\'ete dernier en trois jours. Un depaysement total.', 'approved', '2026-03-10 09:00:00'),
(50, 109, 5, 'Excellente nouvelle ! Trop de jeunes Charentais doivent quitter la region pour se former au numerique.', 'approved', '2026-03-12 11:00:00'),
(51, 109, 7, 'Je suis enseignant dans un lycee technique et j\'attends avec impatience cet etablissement partenaire.', 'approved', '2026-03-13 08:00:00'),
(52, 109, 3, 'La filiere DWWM dans ce lycee, c\'est exactement ce qui manquait ! La formation AFEC etait bien mais un lycee dedie va former plus de developpeurs locaux.', 'approved', '2026-03-13 10:00:00'),
(53, 109, 8, 'Est-ce que des adultes en reconversion pourront integrer ce lycee via des dispositifs de formation continue ?', 'pending', '2026-03-14 09:00:00'),
(54, 110, 6, 'Le jardin des douves de l\'Hotel de Ville, je le decouvre grace a cet article ! J\'habite Angouleme depuis dix ans et je ne savais pas qu\'il existait.', 'approved', '2026-03-18 13:00:00'),
(55, 110, 4, 'Le parc de la Rhonie est un endroit que j\'affectionne pour la photo naturaliste. J\'y ai photographie sept especes de libellules en une matinee.', 'approved', '2026-03-19 08:00:00'),
(56, 110, 9, 'Angouleme a vraiment tout pour plaire. Il faudrait mieux communiquer pour attirer plus de touristes !', 'approved', '2026-03-19 10:00:00');
