-- =============================================================
-- seed.sql — Données de test
-- À importer APRÈS init.sql (qui contient la structure +
-- catégories + lieux + compte Admin)
--
-- Contient :
--   9 utilisateurs membres (Admin exclu)
--   58 articles
--   88 sections de contenu
--   11 événements
--   12 intérêts événements
--   55 commentaires
--   68 likes
--   102 vues
-- =============================================================
 
USE bienvenue_blog;
 
SET FOREIGN_KEY_CHECKS=0;
 
-- ── users ─────────────────────────────────────────────
 
-- ── posts ─────────────────────────────────────────────
 
-- ── post_sections ─────────────────────────────────────
 
-- ── events ────────────────────────────────────────────
 
-- ── event_interests ───────────────────────────────────
 
-- ── comments ──────────────────────────────────────────
 
-- ── likes ─────────────────────────────────────────────
 
-- ── post_views ────────────────────────────────────────
 
SET FOREIGN_KEY_CHECKS=1;
 
SELECT CONCAT(
    '✅ Seed OK — ',
    (SELECT COUNT(*) FROM posts), ' articles, ',
    (SELECT COUNT(*) FROM users)-1, ' membres, ',
    (SELECT COUNT(*) FROM comments), ' commentaires, ',
    (SELECT COUNT(*) FROM likes), ' likes'
) AS statut;